function evaluerRobustesseMotDePasse(mdp) {
    let score = 0;
    let longueur = mdp.length;
    let majuscules = /[A-Z]/.test(mdp);
    let minuscules = /[a-z]/.test(mdp);
    let chiffres = /[0-9]/.test(mdp);
    let caracteresSpeciaux = /[^A-Za-z0-9]/.test(mdp);

    // Longueur du mot de passe
    if (longueur >= 8) score += 1;
    if (longueur >= 12) score += 1;
    if (longueur >= 16) score += 1;

    // Types de caractères
    if (majuscules) score += 1;
    if (minuscules) score += 1;
    if (chiffres) score += 1;
    if (caracteresSpeciaux) score += 1;

    // Séquences répétées
    for (let i = 0; i < mdp.length - 2; i++) {
        if (mdp[i] === mdp[i+1] && mdp[i+1] === mdp[i+2]) {
            score -= 1;
            break;
        }
    }

    // Séquences courantes
    const sequencesCommunes = ["123", "abc", "password", "qwerty"];
    for (let seq of sequencesCommunes) {
        if (mdp.includes(seq)) {
            score -= 2;
            break;
        }
    }

    // Résultat
    if (score <= 2) return "Faible";
    if (score <= 4) return "Modéré";
    if (score <= 6) return "Fort";
    return "Très fort";
}

