    mavenCentral()
}

dependencies {
    implementation 'org.bitcoinj:bitcoinj-core:0.16.0'
    implementation 'org.bouncycastle:bcprov-jdk15on:1.72'
    implementation 'org.slf4j:slf4j-simple:2.0.7'
